sql:
SELECT road_name
FROM roads
WHERE speed_limit > 50;

SELECT road_id
FROM traffic_data
WHERE traffic_volume = (SELECT MAX(traffic_volume) FROM traffic_data);

external_knowledge:
- "Recently accessed" refers to roads accessed within the last month; 
- "High traffic volume" means traffic volume exceeding 1000; 
- Average speed is calculated based on data records with more than three entries for each road to ensure reliability.

sql:
SELECT AVG(road_width) AS average_width, SUM(road_length) AS total_length
FROM roads
WHERE region_id = 0;

SELECT region_id, COUNT(*) AS number_of_roads
FROM roads
GROUP BY region_id;

SELECT road_name, road_length
FROM roads
ORDER BY road_length DESC;

external_knowledge:
- High traffic volume refers to an average traffic volume exceeding 1000 vehicles; 
- Residential and arterial refer to specific road types as defined in the road_types table; 
- The year 2023 is the period of interest for traffic data collection.

sql:
SELECT road_id, condition_date, condition_type, condition_rating
FROM road_conditions
ORDER BY condition_rating DESC;

SELECT road_name
FROM roads
WHERE region_id = (SELECT region_id FROM regions WHERE region_name = 'Stoke-on-Trent');
